def cast_filter_value(value_str: str, operator: str):
    """Attempt to cast string value to appropriate Python type."""
    if value_str is None:
        return None
    # Try int
    try:
        return int(value_str)
    except (ValueError, TypeError):
        pass
    # Try float
    try:
        return float(value_str)
    except (ValueError, TypeError):
        pass
    # Try boolean
    if value_str.lower() in ("true", "false"):
        return value_str.lower() == "true"
    # Return as string
    return value_str


def build_search_query(search_input) -> Tuple[SecureQueryBuilder, SecureQueryBuilder]:
    """Build query from GraphQL search input. Returns (data_builder, count_builder)."""
    table_name = search_input.table
    builder = SecureQueryBuilder(table_name)

    # Select specific fields
    if search_input.select_fields:
        builder.select(search_input.select_fields)

    # Apply filters
    if search_input.filters:
        for f in search_input.filters:
            op = f.operator
            if op in ("is_null", "is_not_null"):
                builder.where(f.field, op)
            elif op in ("in", "not_in"):
                if not f.values:
                    raise QueryBuildError(f"Operator {op} requires 'values' list.")
                cast_values = [cast_filter_value(v, op) for v in f.values]
                builder.where(f.field, op, cast_values)
            elif op == "between":
                if not f.values or len(f.values) != 2:
                    raise QueryBuildError("BETWEEN operator requires exactly 2 values in 'values' list.")
                cast_values = [cast_filter_value(v, op) for v in f.values]
                builder.where(f.field, op, cast_values)
            else:
                value = cast_filter_value(f.value, op)
                builder.where(f.field, op, value)

    # Full-text search
    if search_input.text_search:
        fields = search_input.text_search_fields
        if not fields:
            fields = list(ALLOWED_TABLES[table_name]["searchable"])
        builder.search_text(fields, search_input.text_search)

    # Sorting
    if search_input.sort:
        for s in search_input.sort:
            builder.order_by(s.field, s.direction or "asc")

    # Pagination
    pagination = search_input.pagination
    limit = 20
    offset = 0
    if pagination:
        limit = pagination.limit if pagination.limit is not None else 20
        offset = pagination.offset if pagination.offset is not None else 0
    builder.limit(limit)
    builder.offset(offset)

    return builder


