            rows = execute_query(sql, params)

            # Build and execute count query
            count_sql, count_params = builder.build_count()
            total_count = execute_count(count_sql, count_params)

            # Determine pagination
            pagination = input.pagination
            limit = 20
            offset = 0
            if pagination:
                limit = pagination.limit if pagination.limit is not None else 20
                offset = pagination.offset if pagination.offset is not None else 0

            has_more = (offset + limit) < total_count

            # Sanitize debug output (show query structure but not parameter values)
